files = ["src/**/*.go", "README.md"]
workdir = "/tmp/work"
sub_agents = ["helper", "reviewer"]

[memory]
enabled = true
path = "/tmp/memory"

[params]
temperature = 0.7
max_tokens = 4096
`
	writeAgentFile(t, agentsDir, "full-agent", tomlContent)

